// client/src/pages/agent/AgentDashboard.js
import React, { useState, useEffect } from "react";
import api from "../../services/api";
import useAuth from "../../hooks/useAuth";

const AgentDashboard = () => {
  const [parcels, setParcels] = useState([]);
  const { logout } = useAuth();

  useEffect(() => {
    const fetchAssignedParcels = async () => {
      try {
        const { data } = await api.get("/agent/parcels");
        setParcels(data);
      } catch (error) {
        console.error("Failed to fetch assigned parcels", error);
      }
    };
    fetchAssignedParcels();
  }, []);

  const handleStatusUpdate = async (
    parcelId,
    status,
    location = "Updated Location"
  ) => {
    try {
      await api.put(`/agent/parcels/${parcelId}/status`, { status, location });
      setParcels((prev) =>
        prev.map((p) => (p._id === parcelId ? { ...p, status } : p))
      );
    } catch (error) {
      console.error("Failed to update status", error);
    }
  };

  // Note: The optimized route view would use the Google Maps API
  // It would take the list of delivery addresses and generate a route.

  return (
    <div>
      <h1>Delivery Agent Dashboard</h1>
      <button onClick={logout}>Logout</button>
      <hr />
      <h2>My Assigned Parcels</h2>
      {parcels.length > 0 ? (
        <ul>
          {parcels.map((p) => (
            <li key={p._id}>
              Parcel ID: {p._id} <br />
              From: {p.pickupAddress} <br />
              To: {p.deliveryAddress} <br />
              Status: <strong>{p.status}</strong>
              <div>
                <select
                  onChange={(e) => handleStatusUpdate(p._id, e.target.value)}
                >
                  <option value="">Update Status</option>
                  <option value="Picked Up">Picked Up</option>
                  <option value="In Transit">In Transit</option>
                  <option value="Delivered">Delivered</option>
                  <option value="Failed">Failed</option>
                </select>
              </div>
            </li>
          ))}
        </ul>
      ) : (
        <p>No parcels assigned.</p>
      )}
    </div>
  );
};

export default AgentDashboard;
